from functools import lru_cache

def fibonacci(n):
    @lru_cache(maxsize=None)
    def fib(k):
        if k <= 0:
            return 0
        if k == 1:
            return 1
        return fib(k - 1) + fib(k - 2)
    return fib(n)

def fibonacci(n):
    if n <= 0:
        return 0
    if n == 1:
        return 1
    prev, curr = 0, 1
    for _ in range(2, n + 1):
        prev, curr = curr, prev + curr
    return curr

def fibonacci(n):
    if n < 0:
        return 0
    if n == 0:
        return 0
    def matrix_mult(A, B):
        return [
            [A[0][0]*B[0][0] + A[0][1]*B[1][0], A[0][0]*B[0][1] + A[0][1]*B[1][1]],
            [A[1][0]*B[0][0] + A[1][1]*B[1][0], A[1][0]*B[0][1] + A[1][1]*B[1][1]]
        ]
    def matrix_pow(M, p):
        result = [[1, 0], [0, 1]]
        while p > 0:
            if p & 1:
                result = matrix_mult(result, M)
            M = matrix_mult(M, M)
            p >>= 1
        return result
    return matrix_pow([[1, 1], [1, 0]], n)[0][1]

def fibonacci(n):
    if n < 0:
        return 0
    def fast_doubling(k):
        if k == 0:
            return (0, 1)
        a, b = fast_doubling(k >> 1)
        c = a * (2 * b - a)
        d = a * a + b * b
        if k & 1:
            return (d, c + d)
        return (c, d)
    return fast_doubling(n)[0]

def fibonacci(n):
    if n < 0:
        return 0
    def fast_doubling_iter(n):
        a, b = 0, 1
        bits = []
        while n > 0:
            bits.append(n & 1)
            n >>= 1
        for bit in reversed(bits):
            c = a * (2 * b - a)
            d = a * a + b * b
            if bit:
                a, b = d, c + d
            else:
                a, b = c, d
        return a
    return fast_doubling_iter(n)
